		command: "app.open",
		result: {
			projectId,
			verboseContext: toAppVerboseContext(target),
			app: {
				id: deploymentsResult.app.id,
				name: deploymentsResult.app.name
			},
			url: deploymentsResult.app.liveUrl,
			opened: shouldOpen
		},
